import { ethers } from "ethers";

const RPC_URL = process.env.RPC_URL || "https://mainnet.infura.io/v3/YOUR_INFURA_KEY";
const PRIVATE_KEYS = (process.env.PRIVATE_KEYS || "YOUR_PRIVATE_KEY").split(",").map(k => k.trim()).filter(Boolean);

if (PRIVATE_KEYS.length === 0 || PRIVATE_KEYS[0] === "YOUR_PRIVATE_KEY") {
  throw new Error("Set PRIVATE_KEYS environment variable with one or more comma-separated private keys.");
}

const provider = new ethers.JsonRpcProvider(RPC_URL);

const wallets = PRIVATE_KEYS.map(pk => new ethers.Wallet(pk, provider));

export function getWallet(index = 0) {
  if (!wallets[index]) throw new Error(`Wallet at index ${index} not found`);
  return wallets[index];
}

export async function getBalance(address) {
  return await provider.getBalance(address);
}

export async function sendETH({
  fromWalletIndex = 0,
  to,
  amountEth,
  gasLimit,
  maxFeePerGasGwei,
  maxPriorityFeePerGasGwei,
  nonce
}) {
  if (!to) throw new Error("Recipient address is required");
  if (!amountEth) throw new Error("amountEth is required");

  const wallet = getWallet(fromWalletIndex);

  const feeData = await provider.getFeeData();

  const tx = {
    to,
    value: ethers.parseEther(amountEth.toString())
  };

  if (gasLimit) tx.gasLimit = BigInt(gasLimit);
  tx.maxFeePerGas = maxFeePerGasGwei
    ? ethers.parseUnits(maxFeePerGasGwei.toString(), "gwei")
    : feeData.maxFeePerGas;
  tx.maxPriorityFeePerGas = maxPriorityFeePerGasGwei
    ? ethers.parseUnits(maxPriorityFeePerGasGwei.toString(), "gwei")
    : feeData.maxPriorityFeePerGas;

  if (nonce !== undefined) tx.nonce = nonce;

  const response = await wallet.sendTransaction(tx);
  const receipt = await response.wait();

  return {
    hash: response.hash,
    from: response.from,
    to: response.to,
    value: tx.value.toString(),
    receipt
  };
}

export function getContract({ address, abi, walletIndex = 0, readOnly = false }) {
  if (!address) throw new Error("Contract address is required");
  if (!abi) throw new Error("Contract ABI is required");

  const signerOrProvider = readOnly ? provider : getWallet(walletIndex);
  return new ethers.Contract(address, abi, signerOrProvider);
}

export async function callContractMethod({
  contractAddress,
  abi,
  method,
  args = [],
  walletIndex = 0,
  readOnly = false
}) {
  const contract = getContract({
    address: contractAddress,
    abi,
    walletIndex,
    readOnly
  });

  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }

  return await contract[method](...args);
}

export async function sendContractTransaction({
  contractAddress,
  abi,
  method,
  args = [],
  walletIndex = 0,
  overrides = {}
}) {
  const contract = getContract({
    address: contractAddress,
    abi,
    walletIndex,
    readOnly: false
  });

  if (typeof contract[method] !== "function") {
    throw new Error(`Method ${method} does not exist on contract`);
  }

  const txResponse = await contract[method](...args, overrides);
  const receipt = await txResponse.wait();

  return {
    hash: txResponse.hash,
    receipt
  };
}

export async function estimateEthTransferGas({
  fromWalletIndex = 0,
  to,
  amountEth
}) {
  const wallet = getWallet(fromWalletIndex);
  return await provider.estimateGas({
    from: wallet.address,
    to,
    value: ethers.parseEther(amountEth.toString())
  });
}

export async function estimateContractGas({
  contractAddress,
  abi,
  method,
  args = [],
  walletIndex = 0,
  valueEth
}) {
  const wallet = getWallet(walletIndex);
  const contract = new ethers.Contract(contractAddress, abi, wallet);

  if (!contract[method] || !contract[method].estimateGas) {
    throw new Error(`Method ${method} does not exist or cannot estimate gas`);
  }

  const overrides = {};
  if (valueEth) overrides.value = ethers.parseEther(valueEth.toString());

  return await contract[method].estimateGas(...args, overrides);
}

export async function getTransaction(hash) {
  return await provider.getTransaction(hash);
}

export async function getTransactionReceipt(hash) {
  return await provider.getTransactionReceipt(hash);
}

export async function getNetwork() {
  return await provider.getNetwork();
}

export async function getCurrentBlockNumber() {
  return await provider.getBlockNumber();
}

export async function waitForTransaction(hash, confirmations = 1, timeout = 0) {
  return await provider.waitForTransaction(hash, confirmations, timeout);
}

export default {
  provider,
  wallets,
  getWallet,
  getBalance,
  sendETH,
  getContract,
  callContractMethod,
  sendContractTransaction,
  estimateEthTransferGas,
  estimateContractGas,
  getTransaction,
  getTransactionReceipt,
  getNetwork,
  getCurrentBlockNumber,
  waitForTransaction
};